#include <stdio.h>
#include <stdlib.h>

int cmp_ll(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    if (x < y) return -1;
    if (x > y) return 1;
    return 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *vals = (long long *)malloc((N + 1) * sizeof(long long));
        long long pref = 0;
        vals[0] = 0; // V[0]
        for (int i = 1; i <= N; ++i) {
            long long x;
            scanf("%lld", &x);
            pref += x;
            vals[i] = pref - i; // V[i]
        }
        qsort(vals, N + 1, sizeof(long long), cmp_ll);
        long long ans = 0;
        long long cnt = 1;
        for (int i = 1; i <= N; ++i) {
            if (vals[i] == vals[i - 1]) {
                ++cnt;
            } else {
                ans += cnt * (cnt - 1) / 2;
                cnt = 1;
            }
        }
        ans += cnt * (cnt - 1) / 2; // last group
        printf("%lld\n", ans);
        free(vals);
    }
    return 0;
}

